query:
SELECT 
  (SELECT COUNT(*) FROM leads) as total_geral,
  (SELECT COUNT(*) FROM leads WHERE corretorId IN (
    SELECT id FROM users WHERE name LIKE '%Teste%' OR name LIKE '%Test%' OR name LIKE '%Rank%' OR name LIKE '%Batch%' OR name LIKE '%Sheets%' OR name LIKE '%Duplica%' OR name LIKE '%Visitas%' OR name LIKE '%Performance%' OR name = 'Corretor 2' OR name = 'João Silva Atualizado' OR name LIKE 'João Silva Teste%' OR name = 'Sem nome' OR name = 'Juliana Alonso'
  ) OR nome LIKE 'Lead Teste%' OR nome LIKE 'Lead Batch%' OR nome LIKE 'Lead Rank%' OR nome LIKE 'Lead C0 %' OR nome LIKE 'Lead C1 %' OR nome LIKE 'Lead C2 %' OR nome LIKE 'Lead Kanban Test%') as leads_teste,
  (SELECT COUNT(*) FROM users WHERE name LIKE '%Teste%' OR name LIKE '%Test%' OR name LIKE '%Rank%' OR name LIKE '%Batch%' OR name LIKE '%Sheets%' OR name LIKE '%Duplica%' OR name LIKE '%Visitas%' OR name LIKE '%Performance%' OR name = 'Corretor 2' OR name = 'João Silva Atualizado' OR name LIKE 'João Silva Teste%' OR name = 'Sem nome' OR name = 'Juliana Alonso') as usuarios_teste;

